-- Repair deterministic IDs generated by migration 0010 before strict TypeID
-- suffix validation was introduced. The old migration used raw md5 substrings,
-- whose first character may be 8-f; TypeID suffixes require 0-7 there.
--
-- This migration is intentionally narrow: it only rewrites the synthetic
-- legacy_migration source IDs and structural source_links IDs minted by 0010.
-- Existing app-level node/claim IDs are left stable.

SELECT pg_advisory_xact_lock(1777558586, 14);
--> statement-breakpoint

CREATE TEMP TABLE _legacy_source_id_rewrites ON COMMIT DROP AS
SELECT
  "id" AS old_id,
  'src_0' || substring(md5('legacy_migration:' || "user_id") from 1 for 25) AS new_id
FROM "sources"
WHERE "type" = 'legacy_migration'
  AND "external_id" = 'legacy_migration:' || "user_id"
  AND "id" = 'src_' || substring(md5('legacy_migration:' || "user_id") from 1 for 26)
  AND "id" <> 'src_0' || substring(md5('legacy_migration:' || "user_id") from 1 for 25)
  AND NOT EXISTS (
    SELECT 1
    FROM "sources" target
    WHERE target."id" = 'src_0' || substring(md5('legacy_migration:' || "sources"."user_id") from 1 for 25)
  );
--> statement-breakpoint

CREATE TEMP TABLE _source_link_id_rewrites ON COMMIT DROP AS
SELECT
  "id" AS old_id,
  'sln_0' || substring(md5('structural_source_link:' || "source_id" || ':' || "node_id") from 1 for 25) AS new_id
FROM "source_links"
WHERE "id" = 'sln_' || substring(md5('structural_source_link:' || "source_id" || ':' || "node_id") from 1 for 26)
  AND "id" <> 'sln_0' || substring(md5('structural_source_link:' || "source_id" || ':' || "node_id") from 1 for 25)
  AND NOT EXISTS (
    SELECT 1
    FROM "source_links" target
    WHERE target."id" = 'sln_0' || substring(md5('structural_source_link:' || "source_links"."source_id" || ':' || "source_links"."node_id") from 1 for 25)
  );
--> statement-breakpoint

UPDATE "source_links" sl
SET "id" = rewrites.new_id
FROM _source_link_id_rewrites rewrites
WHERE sl."id" = rewrites.old_id;
--> statement-breakpoint

DO $$
BEGIN
  IF EXISTS (
    SELECT 1 FROM pg_constraint WHERE conname = 'claims_source_id_sources_id_fk'
  ) THEN
    ALTER TABLE "claims" DROP CONSTRAINT "claims_source_id_sources_id_fk";
  END IF;

  IF EXISTS (
    SELECT 1 FROM pg_constraint WHERE conname = 'source_links_source_id_sources_id_fk'
  ) THEN
    ALTER TABLE "source_links" DROP CONSTRAINT "source_links_source_id_sources_id_fk";
  END IF;
END $$;
--> statement-breakpoint

UPDATE "claims" c
SET "source_id" = rewrites.new_id
FROM _legacy_source_id_rewrites rewrites
WHERE c."source_id" = rewrites.old_id;
--> statement-breakpoint

UPDATE "source_links" sl
SET "source_id" = rewrites.new_id
FROM _legacy_source_id_rewrites rewrites
WHERE sl."source_id" = rewrites.old_id;
--> statement-breakpoint

UPDATE "sources" s
SET "parent_source" = rewrites.new_id
FROM _legacy_source_id_rewrites rewrites
WHERE s."parent_source" = rewrites.old_id;
--> statement-breakpoint

UPDATE "sources" s
SET "id" = rewrites.new_id
FROM _legacy_source_id_rewrites rewrites
WHERE s."id" = rewrites.old_id;
--> statement-breakpoint

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint WHERE conname = 'claims_source_id_sources_id_fk'
  ) THEN
    ALTER TABLE "claims"
      ADD CONSTRAINT "claims_source_id_sources_id_fk"
      FOREIGN KEY ("source_id") REFERENCES "public"."sources"("id")
      ON DELETE CASCADE ON UPDATE NO ACTION;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint WHERE conname = 'source_links_source_id_sources_id_fk'
  ) THEN
    ALTER TABLE "source_links"
      ADD CONSTRAINT "source_links_source_id_sources_id_fk"
      FOREIGN KEY ("source_id") REFERENCES "public"."sources"("id")
      ON DELETE CASCADE ON UPDATE NO ACTION;
  END IF;
END $$;
